from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about airports (or related entities) into a single
    fluent sentence. Uses relative clauses to create coherent complex sentences.
    """
    if not triples:
        return ""

    def _clean(val: str) -> str:
        """Remove surrounding quotes if present."""
        return val.strip('"').strip("'")

    def _format_predicate(p: str, o: str, include_subject: bool = True, subject: str = None) -> str:
        """Format a triple into natural language."""
        o = _clean(o)

        if p == "cityServed":
            return f"{subject} serves the city of {o}" if include_subject else f"serves the city of {o}"
        elif p == "location":
            return f"{subject} is located in {o}" if include_subject else f"is located in {o}"
        elif p == "country":
            return f"{subject} is in {o}" if include_subject else f"is in {o}"
        elif p == "isPartOf":
            return f"{subject} is part of {o}" if include_subject else f"is part of {o}"
        elif p == "elevationAboveTheSeaLevel":
            return f"{o} metres above sea level"
        elif p == "elevationAboveTheSeaLevelInFeet":
            return f"{o} feet above sea level"
        elif p == "elevationAboveTheSeaLevelInMetres":
            return f"{o} metres above sea level"
        elif p == "operatingOrganisation":
            return f"operated by {o}"
        elif p == "runwaySurfaceType":
            return f"with runway surface {o}"
        elif p == "runwayName":
            return f"with runway name {o}"
        elif p == "runwayLength":
            return f"with runway length {o}"
        elif p == "iataLocationIdentifier":
            return f"IATA code {o}"
        elif p == "icaoLocationIdentifier":
            return f"ICAO code {o}"
        elif p == "locationIdentifier":
            return f"location identifier {o}"
        elif p.endswith("RunwayLengthFeet"):
            idx = p.split("Runway")[0].lower()
            return f"{idx} runway {o} feet"
        elif p.endswith("RunwayLengthMetre"):
            idx = p.split("Runway")[0].lower()
            return f"{idx} runway {o} metres"
        elif p.endswith("RunwaySurfaceType"):
            idx = p.split("Runway")[0].lower()
            return f"{idx} runway surface {o}"
        elif p.endswith("RunwayNumber"):
            idx = p.split("Runway")[0].lower()
            return f"{idx} runway number {o}"
        elif p == "nativeName":
            return f"known locally as {o}"
        elif p == "owner":
            return f"owned by {o}"
        elif p == "capital":
            return f"capital is {o}"
        elif p == "language":
            return f"speaks {o}"
        elif p == "officialLanguage":
            return f"official language is {o}"
        elif p == "currency":
            return f"uses {o}"
        elif p == "demonym":
            return f"people are called {o}"
        else:
            return f"has {p} {o}"

    # Group triples by subject to build coherent sentences
    subject_triples: dict[str, list[Triple]] = {}
    for t in triples:
        if t.subject not in subject_triples:
            subject_triples[t.subject] = []
        subject_triples[t.subject].append(t)

    # Find the main subject (usually the airport)
    main_subject = triples[0].subject if triples else ""
    other_subjects = [s for s in subject_triples.keys() if s != main_subject]

    # Build the main sentence with better chaining
    main_parts = []
    for t in triples:
        if t.subject == main_subject:
            main_parts.append(_format_predicate(t.predicate, t.object, include_subject=True, subject=t.subject))

    # Build the sentence with relative clauses to avoid repetition
    if main_parts:
        sentence = main_parts[0]

        # Collect location-related info from other subjects for relative clauses
        location_info = []
        for other_subj in other_subjects:
            other_triples = subject_triples[other_subj]
            for t in other_triples:
                if t.predicate in ["country", "isPartOf", "capital", "language", "officialLanguage"]:
                    location_info.append((other_subj, t.predicate, t.object))

        # Add remaining main parts with appropriate connectors
        for i, part in enumerate(main_parts[1:], 1):
            if i == 1:
                sentence += ", " + part
            else:
                sentence += ", and " + part

        # Add location hierarchy information with relative clauses (avoid repetition)
        if location_info:
            # Group by the other subject for cleaner chaining
            prev_subj = None
            for subj, pred, obj in location_info:
                if subj != prev_subj:
                    if prev_subj is not None:
                        sentence += ")"
                    sentence += f", which is {pred} {obj}"
                    prev_subj = subj
                else:
                    sentence += f" and {pred} {obj}"
            if prev_subj is not None:
                sentence += ")"

        sentence += "."
        return sentence[0].upper() + sentence[1:]

    return ""

# EVOLVE-BLOCK-END

